import java.nio.file.*;import java.util.*;
public class Example{
 public static void main(String[]args)throws Exception{Brush.Point[] raw={p(500,520),p(450,450),p(390,395),p(320,370),p(250,370),p(180,390),p(130,450),p(120,520),p(155,585),p(220,635),p(300,650),p(380,620),p(440,570),p(500,520),p(560,465),p(620,410),p(700,370),p(770,380),p(830,420),p(870,480),p(875,545),p(845,610),p(790,660),p(720,675),p(650,655),p(585,610),p(540,560),p(500,520)};List<Brush.Point>points=Arrays.asList(raw);if(!Brush.buildRoundedDrawingPath(List.of(p(0,0),p(100,0),p(100,100)),40).equals("M 0 0 L 55 0 Q 100 0 100 45 L 100 100"))throw new AssertionError();if(Brush.sampleAt(Brush.prepareArcLengthPath(List.of(p(0,0),p(100,0)),.5),.5,40).angle!=0)throw new AssertionError();Path input=Path.of(args.length>0?args[0]:"assets/example.webp"),output=Path.of(args.length>1?args[1]:"generated/java.svg");Files.createDirectories(output.getParent());Brush.Options o=new Brush.Options();o.magicGradient=true;String svg=Brush.renderSvg(Files.readAllBytes(input),"image/webp",1000,1000,points,"🤝 best friends forever",o);if(!svg.contains("data:image/webp;base64,"))throw new AssertionError();Files.writeString(output,svg);System.out.println("Wrote "+output);}
 static Brush.Point p(double x,double y){return new Brush.Point(x,y);}
}
